namespace TranSmart.Service.Leave
{
    public partial interface IAdjustLeaveService : IBaseService<AdjustLeave>
    {

    }

    public partial class AdjustLeaveService : BaseService<AdjustLeave>, IAdjustLeaveService
    {
        public AdjustLeaveService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task<AdjustLeave> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<AdjustLeave>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Employee).Include(x => x.LeaveType),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<AdjustLeave>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<AdjustLeave>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Employee.Name.Contains(search.Name)
                     || x.LeaveType.Name.Contains(search.Name)),
                include: i => i.Include(x => x.Employee).Include(x => x.LeaveType),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Employee.Name", ascending: !search.IsDescend);
        }
    }
